// Normalizza output Apollo.io API
const data = $input.first().json;
const organizations = data.organizations || data.companies || [];

if (!organizations.length) {
  console.log('Nessuna azienda trovata');
  return [];
}

const results = organizations.map(org => {
  // Key contacts (people con ruoli C-level)
  const keyContacts = (org.organization_contacts || org.contacts || []).slice(0, 5).map(c => ({
    name: `${c.first_name || ''} ${c.last_name || ''}`.trim(),
    role: c.title || c.headline || null,
    email: c.email || null,
    linkedin_url: c.linkedin_url || null,
  })).filter(c => c.name);

  // Tech stack
  const technologies = (org.technologies || org.technology_names || []).slice(0, 10);

  // Score
  let score = 0;
  if (org.primary_domain || org.website_url) score += 20;
  if (org.estimated_num_employees) score += 15;
  if (org.annual_revenue) score += 15;
  if (technologies.length > 0) score += 15;
  if (keyContacts.length > 0) score += 20;
  if (org.linkedin_url) score += 15;

  return {
    json: {
      name: org.name || org.organization_name,
      industry: org.industry || org.primary_industry || null,
      size_range: org.estimated_num_employees
        ? org.estimated_num_employees <= 50 ? '1-50'
          : org.estimated_num_employees <= 200 ? '51-200'
          : org.estimated_num_employees <= 1000 ? '201-1000'
          : '1000+'
        : null,
      website: org.primary_domain
        ? `https://${org.primary_domain}`
        : org.website_url || null,
      headquarters: [org.city, org.country].filter(Boolean).join(', ') || null,
      employee_count: org.estimated_num_employees || null,
      revenue_range: org.annual_revenue
        ? org.annual_revenue < 1000000 ? '<1M€'
          : org.annual_revenue < 10000000 ? '1-10M€'
          : org.annual_revenue < 50000000 ? '10-50M€'
          : '50M€+'
        : null,
      technologies: technologies.length ? technologies : null,
      key_contacts: keyContacts.length ? keyContacts : null,
      score: Math.min(score, 100),
    }
  };
});

return results;

const response = $input.first().json;
console.log(`✅ Apollo: ${response.inserted} aziende inserite, ${response.received} ricevute`);
return [{ json: { status: 'ok', ...response } }];
